mapper.select:
/* eventCodePrmtMapper.getEventCodePrmtList */ SELECT DTL.EVNT_CD_PRMT AS EVNT_CD , DTL.EVNT_CD_NM AS EVNT_NM , SUB.CONTRACT_NUM , SUB.SUB_LINK_NAME , SUB.SUBSCRIBER_NO , DTL.FST_RATE_NM , DTL.LST_RATE_NM , SUB.LST_COM_ACTV_DATE , DTL.MOVE_COMPANY_NM , DTL.RECOMMEND_INFO FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL DTL WHERE SUB.CONTRACT_NUM = DTL.CONTRACT_NUM AND DTL.EVNT_CD_PRMT IS NOT NULL
AND SUB.LST_COM_ACTV_DATE BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND DTL.EVNT_CD_PRMT = #{srchEventCd}
ORDER BY SUB.LST_COM_ACTV_DATE DESC
